package com.example.webhookhandler.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.client.HttpComponentsClientHttpRequestFactory;
import org.springframework.web.client.RestTemplate;

import java.time.Duration;

@Configuration
public class RestClientConfig {

    @Bean
    public RestTemplate restTemplate() {
        HttpComponentsClientHttpRequestFactory factory = new HttpComponentsClientHttpRequestFactory();
        factory.setConnectTimeout((int) Duration.ofSeconds(5).toMillis());
        factory.setReadTimeout((int) Duration.ofSeconds(10).toMillis());
        return new RestTemplate(factory);
    }
}

package com.example.webhookhandler.service;

import com.example.webhookhandler.dto.WebhookResponse;
import org.springframework.stereotype.Service;
import org.springframework.web.client.HttpStatusCodeException;
import org.springframework.web.client.ResourceAccessException;
import org.springframework.web.client.RestTemplate;

@Service
public class ContentFetchService {

    private final RestTemplate restTemplate;

    public ContentFetchService(RestTemplate restTemplate) {
        this.restTemplate = restTemplate;
    }

    public WebhookResponse fetchContent(String url) {
        try {
            var entity = restTemplate.getForEntity(url, String.class);
            return WebhookResponse.success(url, entity.getStatusCode().value(), entity.getBody());
        } catch (HttpStatusCodeException ex) {
            return WebhookResponse.failure(url, "HTTP error: " + ex.getStatusCode().value() + " " + ex.getStatusText() + " - " + ex.getResponseBodyAsString());
        } catch (ResourceAccessException ex) {
            return WebhookResponse.failure(url, "Connection error: " + ex.getMessage());
        } catch (Exception ex) {
            return WebhookResponse.failure(url, "Unexpected error: " + ex.getMessage());
        }
    }
}

package com.example.webhookhandler.exception;

import com.example.webhookhandler.dto.WebhookResponse;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.util.LinkedHashMap;
import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<Map<String, Object>> handleValidation(MethodArgumentNotValidException ex) {
        Map<String, Object> body = new LinkedHashMap<>();
        body.put("success", false);
        body.put("error", ex.getBindingResult().getFieldErrors().stream()
                .findFirst()
                .map(err -> err.getField() + ": " + err.getDefaultMessage())
                .orElse("Validation failed"));
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(body);
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<WebhookResponse> handleAny(Exception ex) {
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body(WebhookResponse.failure(null, ex.getMessage()));
    }
}